///|
test "grader catches empty packets across the public boundary" {
  try @api.decode_tag(b"") catch {
    @api.DecodeError::Empty => ()
    _ => fail("wrong error kind")
  } noraise {
    _ => fail("expected DecodeError::Empty")
  }
  assert_eq(@api.decode_tag(b"\x01later"), "ping")
}

///|
test "grader catches one unknown tag with its payload" {
  try @api.decode_tag(b"\x7fdata") catch {
    @api.DecodeError::Unknown(tag) => assert_eq(tag, b'\x7f')
    _ => fail("wrong error kind")
  } noraise {
    _ => fail("expected DecodeError::Unknown")
  }
  assert_eq(@api.decode_tag(b"\x02later"), "pong")
}

///|
test "grader preserves varied unknown-tag payloads" {
  try @api.decode_tag(b"\x03more") catch {
    @api.DecodeError::Unknown(tag) => assert_eq(tag, b'\x03')
    _ => fail("wrong error kind")
  } noraise {
    _ => fail("expected DecodeError::Unknown")
  }
  try @api.decode_tag(b"\xfe") catch {
    @api.DecodeError::Unknown(tag) => assert_eq(tag, b'\xfe')
    _ => fail("wrong error kind")
  } noraise {
    _ => fail("expected DecodeError::Unknown")
  }
}

///|
test "grader preserves varied valid packets" {
  assert_eq(@api.decode_tag(b"\x01"), "ping")
  assert_eq(@api.decode_tag(b"\x02payload"), "pong")
}
